import json

data = env['data_4']
latest_versions = {}

for row in data:
    name = row['Name']
    version = row['Version']
    vinfo = json.loads(row['VersionInfo'])

    if vinfo.get('IsRelease'):
        ordinal = vinfo.get('Ordinal', 0)
        if name not in latest_versions or ordinal > latest_versions[name]['ordinal']:
            latest_versions[name] = {'version': version, 'ordinal': ordinal}

results = []
for name, info in latest_versions.items():
    results.append(f"{name}: {info['version']}")

print(f"Found {len(results)} packages")
for r in results[:10]:
    print(r)
env['final_results'] = results

